             <button
                type="button"
                onClick={() => initSocialLogin('github')}
                className="flex items-center justify-center gap-2 py-2.5 border border-white/[0.06] bg-white/[0.03] hover:bg-white/[0.07] rounded-full transition-colors text-sm font-medium"
             >
                <Github size={16} />
                GitHub
             </button>
