import React from 'react';
import { AnalysisResult } from '../types';
import { ArrowLeft, ExternalLink, Calendar, Search, LayoutDashboard, FileText, Zap, Bot, ArrowRight, Trash2, Archive } from 'lucide-react';
import PageHeader from '../components/layout/PageHeader';
import { useTranslation } from '../i18n/context';

interface Props {
  history: AnalysisResult[];
  onBack: () => void;
  onView: (analysis: AnalysisResult, tab: 'overview' | 'details' | 'recommendations' | 'preview' | 'archives') => void;
}

const History: React.FC<Props> = ({ history, onBack, onView }) => {
  const { t } = useTranslation();

  const formatDate = (isoString: string) => {
    return new Date(isoString).toLocaleDateString('fr-FR', {
      day: 'numeric',
      month: 'long',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  const getScoreColor = (score: number) => {
    if (score >= 80) return 'text-[var(--success)] border-[var(--success)]/30 bg-[var(--success)]/10';
    if (score >= 60) return 'text-[var(--accent-text)] border-[var(--accent)]/30 bg-[var(--accent-subtle)]';
    return 'text-[var(--error)] border-[var(--error)]/30 bg-[var(--error)]/10';
  };

  return (
    <div className="page-enter">
      <PageHeader title={t.history.title} description={t.history.description} />

      <div className="flex justify-between items-center mb-8">
        <p className="text-[13px] text-[var(--text-tertiary)]">{t.history.subtitle}</p>
        <div className="text-[11px] text-[var(--text-disabled)] bg-white/[0.03] px-3 py-1.5 rounded-md border border-white/[0.06]">
          {history.length} {history.length > 1 ? t.history.analyses : t.history.analysis}
        </div>
      </div>

      {history.length === 0 ? (
        <div className="bg-white/[0.03] border-2 border-dashed border-white/[0.06] rounded-xl p-12 flex flex-col items-center justify-center text-center">
          <div className="w-12 h-12 bg-white/[0.06] rounded-xl flex items-center justify-center mb-4 text-[var(--text-tertiary)]">
            <Search size={24} />
          </div>
          <h3 className="text-[var(--text-primary)] font-medium mb-2">{t.history.noHistory}</h3>
          <p className="text-[13px] text-[var(--text-tertiary)] mb-6 max-w-md">
            {t.history.noHistoryDesc}
          </p>
          <button onClick={onBack} className="px-4 py-2 bg-white text-black text-[13px] font-medium rounded-lg hover:bg-gray-200 transition-colors">
            {t.history.launchNewAudit}
          </button>
        </div>
      ) : (
        <div className="space-y-4">
          {history.map((item, idx) => {
            const hostname = new URL(item.url).hostname;
            return (
              <div key={idx} className="bg-white/[0.03] rounded-xl border border-white/[0.06] overflow-hidden group hover:border-[var(--border-strong)] transition-all">
                {/* Header Card */}
                <div className="p-5 flex flex-col md:flex-row justify-between items-start md:items-center gap-4 border-b border-[var(--border-subtle)]">
                  <div className="flex items-center gap-4">
                    <div className={`w-11 h-11 rounded-xl flex items-center justify-center text-[15px] font-bold border ${getScoreColor(item.globalScore)}`}>
                      {item.globalScore}
                    </div>
                    <div>
                      <h3 className="text-[15px] font-semibold text-[var(--text-primary)] flex items-center gap-2">
                        {hostname}
                        <a href={item.url} target="_blank" rel="noopener noreferrer" className="text-[var(--text-disabled)] hover:text-[var(--text-primary)] transition-colors">
                          <ExternalLink size={12} />
                        </a>
                      </h3>
                      <p className="text-[11px] text-[var(--text-disabled)] flex items-center gap-1 mt-1">
                        <Calendar size={10} /> {formatDate(item.timestamp)}
                      </p>
                    </div>
                  </div>

                  <div className="flex items-center gap-6 text-[13px]">
                    <div className="text-center px-4 border-r border-white/[0.06] last:border-0">
                      <span className="block font-semibold text-[var(--text-primary)]">{Object.keys(item.categories).length}</span>
                      <span className="text-[11px] text-[var(--text-disabled)]">{t.history.categories}</span>
                    </div>
                    <div className="text-center px-4 border-r border-white/[0.06] last:border-0">
                      <span className="block font-semibold text-[var(--accent-text)]">{item.recommendations.length}</span>
                      <span className="text-[11px] text-[var(--text-disabled)]">{t.history.actions}</span>
                    </div>
                    <div className="text-center px-4">
                      <span className={`block font-semibold ${item.aiCitation.probability > 50 ? 'text-[var(--accent-text)]' : 'text-[var(--error)]'}`}>
                        {item.aiCitation.probability}%
                      </span>
                      <span className="text-[11px] text-[var(--text-disabled)]">{t.history.citation}</span>
                    </div>
                  </div>
                </div>

                {/* Quick Navigation Tabs */}
                <div className="bg-[var(--bg-base)] p-1.5 flex flex-col sm:flex-row gap-1">
                  <button
                    onClick={() => onView(item, 'overview')}
                    className="flex-1 flex items-center justify-center gap-2 px-3 py-2.5 rounded-lg hover:bg-white/[0.03] text-[var(--text-tertiary)] hover:text-[var(--text-primary)] transition-colors text-[13px] font-medium"
                  >
                    <LayoutDashboard size={14} className="text-[var(--accent-text)]" />
                    {t.history.overview}
                  </button>
                  <div className="w-px bg-[var(--border-subtle)] hidden sm:block"></div>
                  <button
                    onClick={() => onView(item, 'details')}
                    className="flex-1 flex items-center justify-center gap-2 px-3 py-2.5 rounded-lg hover:bg-white/[0.03] text-[var(--text-tertiary)] hover:text-[var(--text-primary)] transition-colors text-[13px] font-medium"
                  >
                    <FileText size={14} className="text-[var(--accent-text)]" />
                    {t.history.details}
                  </button>
                  <div className="w-px bg-[var(--border-subtle)] hidden sm:block"></div>
                  <button
                    onClick={() => onView(item, 'recommendations')}
                    className="flex-1 flex items-center justify-center gap-2 px-3 py-2.5 rounded-lg hover:bg-white/[0.03] text-[var(--text-tertiary)] hover:text-[var(--text-primary)] transition-colors text-[13px] font-medium"
                  >
                    <Zap size={14} className="text-[var(--accent-text)]" />
                    {t.history.actionPlan}
                  </button>
                  <div className="w-px bg-[var(--border-subtle)] hidden sm:block"></div>
                  <button
                    onClick={() => onView(item, 'archives')}
                    className="flex-1 flex items-center justify-center gap-2 px-3 py-2.5 rounded-lg hover:bg-white/[0.03] text-[var(--text-tertiary)] hover:text-[var(--text-primary)] transition-colors text-[13px] font-medium group/btn"
                  >
                    <Archive size={14} className="text-[var(--accent-text)]" />
                    {t.history.archives}
                    <ArrowRight size={12} className="opacity-0 group-hover/btn:opacity-100 transition-opacity -ml-1 translate-x-1" />
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default History;

import React, { useState, useEffect } from 'react';
import { User } from '../types';
import { Fuel, Check, CreditCard, Loader2, Droplet, Database, ArrowLeft, ShieldCheck, Lock, Infinity, CheckCircle2, FileText, Download, XCircle, LayoutDashboard, RefreshCcw, Wrench } from 'lucide-react';
import jsPDF from 'jspdf';
import StripeCheckout from '../components/StripeCheckout';
import PageHeader from '../components/layout/PageHeader';
import { useTranslation } from '../i18n/context';

interface Props {
  onBack: () => void;
  onRecharge: (amount: number, planLevel: 'free' | 'pro' | 'enterprise') => void;
  user: User | null;
  onNavigate?: (view: string) => void;
  initialPackId?: number | null;
}

const Recharge: React.FC<Props> = ({ onBack, onRecharge, user, onNavigate, initialPackId }) => {
  const { t } = useTranslation();
  const [viewMode, setViewMode] = useState<'list' | 'checkout' | 'result'>('list');
  const [paymentStatus, setPaymentStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [selectedPack, setSelectedPack] = useState<typeof packs[0] | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [invoiceId, setInvoiceId] = useState<string>('');

  const packs = [
    {
      id: 1,
      name: t.rechargeCredits.packJerricanName,
      amount: 50,
      price: 15,
      icon: <Droplet size={32} />,
      popular: false,
      level: 'free' as const,
      features: [t.rechargeCredits.jerricanFeat1, t.rechargeCredits.jerricanFeat2]
    },
    {
      id: 2,
      name: t.rechargeCredits.packPompeName,
      amount: 200,
      price: 49,
      icon: <Fuel size={32} />,
      popular: true,
      level: 'pro' as const,
      features: [t.rechargeCredits.pompeFeat1, t.rechargeCredits.pompeFeat2, t.rechargeCredits.pompeFeat3]
    },
    {
      id: 3,
      name: t.rechargeCredits.packCiterneName,
      amount: 1000,
      price: 199,
      icon: <Database size={32} />,
      popular: false,
      level: 'enterprise' as const,
      features: [t.rechargeCredits.citerneFeat1, t.rechargeCredits.citerneFeat2, t.rechargeCredits.citerneFeat3]
    }
  ];

  useEffect(() => {
    if (initialPackId) {
        const targetPack = packs.find(p => p.id === initialPackId);
        if (targetPack) {
            setSelectedPack(targetPack);
            setViewMode('checkout');
        }
    }
  }, [initialPackId]);

  const handleSelectPack = (pack: typeof packs[0]) => {
    setSelectedPack(pack);
    setViewMode('checkout');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleConfirmPayment = () => {
    if (!selectedPack) return;
    setIsProcessing(true);
    setPaymentStatus('idle');

    setTimeout(() => {
      const isSuccess = Math.random() > 0.1;

      if (isSuccess) {
        onRecharge(selectedPack.amount, selectedPack.level);
        const newInvoiceId = `INV-${new Date().getFullYear()}-${Math.floor(Math.random() * 10000).toString().padStart(4, '0')}`;
        setInvoiceId(newInvoiceId);
        setPaymentStatus('success');
      } else {
        setPaymentStatus('error');
      }

      setIsProcessing(false);
      setViewMode('result');
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }, 2000);
  };

  const generateInvoicePDF = () => {
    if (!selectedPack || !user) return;

    const doc = new jsPDF();
    const priceHT = selectedPack.price;
    const tva = priceHT * 0.20;
    const totalTTC = priceHT + tva;
    const date = new Date().toLocaleDateString('fr-FR');

    doc.setFontSize(22);
    doc.setFont("helvetica", "bold");
    doc.text("CitedBy.ai", 20, 20);

    doc.setFontSize(10);
    doc.setFont("helvetica", "normal");
    doc.text("Facture N° " + invoiceId, 20, 30);
    doc.text("Date : " + date, 20, 35);

    doc.text("Facturé à :", 140, 30);
    doc.setFont("helvetica", "bold");
    doc.text(user.name || "Client", 140, 35);
    doc.setFont("helvetica", "normal");
    doc.text(user.email || "", 140, 40);

    doc.line(20, 55, 190, 55);
    doc.setFont("helvetica", "bold");
    doc.text("Description", 20, 62);
    doc.text("Quantité", 120, 62);
    doc.text("Montant HT", 160, 62);
    doc.line(20, 66, 190, 66);

    doc.setFont("helvetica", "normal");
    doc.text(`Pack GTO Gas: ${selectedPack.name} (${selectedPack.amount} crédits)`, 20, 75);
    doc.text("1", 125, 75);
    doc.text(`${priceHT.toFixed(2)} €`, 160, 75);

    doc.line(20, 90, 190, 90);
    doc.text("Sous-total HT :", 130, 100);
    doc.text(`${priceHT.toFixed(2)} €`, 160, 100);

    doc.text("TVA (20%) :", 130, 107);
    doc.text(`${tva.toFixed(2)} €`, 160, 107);

    doc.setFont("helvetica", "bold");
    doc.setFontSize(12);
    doc.text("Total TTC :", 130, 117);
    doc.text(`${totalTTC.toFixed(2)} €`, 160, 117);

    doc.setFontSize(8);
    doc.setFont("helvetica", "italic");
    doc.text("Merci de votre confiance. Cette facture a été réglée par carte bancaire.", 20, 140);
    doc.text("CitedBy Inc. - 123 Avenue de l'IA, Paris, France - SIRET 123 456 789", 20, 280);

    doc.save(`Facture_${invoiceId}.pdf`);
  };

  const renderList = () => (
    <div className="animate-in fade-in slide-in-from-left duration-500">
        <div className="text-center mb-16">
            <div className="inline-flex items-center justify-center w-16 h-16 bg-accent/20 rounded-2xl mb-6 text-accent border border-accent/20 shadow-[0_0_30px_rgba(168,85,247,0.2)]">
            <Fuel size={32} />
            </div>
            <h1 className="text-4xl font-bold text-white mb-4">GTO <span className="gradient-text">Gas Station</span></h1>
            <p className="text-gray-500 max-w-xl mx-auto text-lg">
            {t.rechargeCredits.heroSubtitle}
            <br />
            <span className="text-sm mt-2 block text-gray-500">{t.rechargeCredits.currentBalance} <span className="text-white font-bold">{user?.credits || 0} Gas</span></span>
            </p>
        </div>

        <div className="grid md:grid-cols-3 gap-8 w-full">
            {packs.map((pack) => (
            <div
                key={pack.id}
                className={`relative bg-white/[0.03] border border-white/[0.06] rounded-xl p-8 flex flex-col transition-all duration-300 hover:transform hover:-translate-y-2 ${
                pack.popular
                    ? 'gradient-border !border-purple-500/30 shadow-[0_0_40px_rgba(168,85,247,0.15)] scale-105 z-10'
                    : ''
                }`}
            >
                {pack.popular && (
                <>
                <div className="absolute -top-4 left-1/2 -translate-x-1/2 bg-gradient-to-r from-purple-500 to-violet-500 text-white font-bold text-xs px-4 py-1.5 rounded-full uppercase tracking-wider shadow-lg shadow-purple-900/40 flex items-center gap-1.5">
                    <span className="animate-pulse">⭐</span> {t.rechargeCredits.bestOffer}
                </div>
                <div className="absolute -top-px -left-px -right-px -bottom-px rounded-2xl bg-gradient-to-r from-purple-500/20 to-violet-500/20 -z-10 blur-sm" />
                </>
                )}

                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center mb-6 ${pack.popular ? 'bg-accent/20 text-accent' : 'bg-white/[0.03] text-gray-500'}`}>
                {pack.icon}
                </div>

                <h3 className="text-xl font-bold text-white mb-2">{pack.name}</h3>
                <div className="flex items-baseline gap-1 mb-6">
                <span className="text-4xl font-bold gradient-text">{pack.amount}</span>
                <span className="text-sm text-gray-500 font-medium">Gas</span>
                </div>

                <ul className="space-y-3 mb-8 flex-1">
                {pack.features.map((feat, i) => (
                    <li key={i} className="flex items-start gap-3 text-sm text-gray-300">
                    <Check size={16} className={`mt-0.5 ${pack.popular ? 'text-accent' : 'text-gray-500'}`} />
                    {feat}
                    </li>
                ))}
                </ul>

                <div className="border-t border-white/[0.06] pt-6 mb-6">
                <div className="flex justify-between items-center mb-2">
                    <span className="text-gray-500">{t.rechargeCredits.priceHT}</span>
                    <span className="text-xl font-bold text-white">{pack.price}€</span>
                </div>
                </div>

                <button
                onClick={() => handleSelectPack(pack)}
                className="w-full py-3.5 btn-gradient font-bold flex items-center justify-center gap-2 transition-all"
                >
                    <CreditCard size={18} /> {t.rechargeCredits.buy}
                </button>
            </div>
            ))}
        </div>

        <p className="text-center text-gray-500 text-xs mt-12">
            {t.rechargeCredits.footerNote}
        </p>
    </div>
  );

  const renderCheckout = () => {
    if (!selectedPack) return null;

    const priceHT = selectedPack.price;
    const tva = priceHT * 0.20;
    const totalTTC = priceHT + tva;

    const showCiterneUpsell = selectedPack.name !== t.rechargeCredits.packCiterneName;
    const showSubscriptionUpsell = user?.plan === 'free';

    return (
        <div className="animate-in fade-in slide-in-from-right duration-500">
            <div className="grid lg:grid-cols-12 gap-8">

                <div className="lg:col-span-8">
                    <StripeCheckout
                      mode="one-time"
                      productName={selectedPack.name}
                      productDescription={`${t.rechargeCredits.packOf} ${selectedPack.amount} ${t.rechargeCredits.creditsGtoGas}`}
                      productIcon={selectedPack.icon}
                      amount={totalTTC}
                      amountDetails={[
                        { label: t.rechargeCredits.unitPriceHT, value: `${priceHT.toFixed(2)} \u20ac` },
                        { label: t.rechargeCredits.serviceFees, value: '0.00 \u20ac' },
                        { label: t.rechargeCredits.vat20, value: `${tva.toFixed(2)} \u20ac` },
                        { label: t.rechargeCredits.totalTTC, value: `${totalTTC.toFixed(2)} \u20ac`, highlight: true, separator: true },
                      ]}
                      userEmail={user?.email}
                      onConfirm={handleConfirmPayment}
                      onBack={() => setViewMode('list')}
                      isProcessing={isProcessing}
                    />
                </div>

                <div className="lg:col-span-4 space-y-4">
                    <h3 className="text-sm font-bold text-gray-500 uppercase tracking-wider mb-2">{t.rechargeCredits.recommendedForYou}</h3>

                    {showCiterneUpsell && (
                        <div className="bg-gradient-to-br from-purple-900/40 to-black border border-purple-500/30 p-5 rounded-2xl relative overflow-hidden group cursor-pointer hover:border-purple-500/60 transition-all" onClick={() => setSelectedPack(packs[2])}>
                            <div className="absolute top-0 right-0 px-2 py-1 bg-purple-500 text-white text-[10px] font-bold rounded-bl-lg">
                                {t.rechargeCredits.bestPricePerUnit}
                            </div>
                            <div className="flex items-center gap-3 mb-3">
                                <div className="p-2 bg-purple-500/20 rounded-full text-purple-400">
                                    <Database size={20} />
                                </div>
                                <div>
                                    <h4 className="font-bold text-white text-sm">{t.rechargeCredits.upgradeToCiterne}</h4>
                                    <p className="text-xs text-purple-200/70">{t.rechargeCredits.save60}</p>
                                </div>
                            </div>
                            <p className="text-xs text-gray-300 mb-3 leading-relaxed">
                                {t.rechargeCredits.citerneUpsellDesc}
                            </p>
                            <button className="w-full py-2 border border-white/[0.06] bg-white/[0.03] rounded-full text-purple-400 text-xs font-bold transition-colors hover:bg-white/[0.08]">
                                {t.rechargeCredits.choosePack199}
                            </button>
                        </div>
                    )}

                    {showSubscriptionUpsell && (
                        <div className="bg-gradient-to-br from-purple-900/40 to-black border border-purple-500/30 p-5 rounded-2xl relative overflow-hidden group cursor-pointer hover:border-purple-500/60 transition-all">
                            <div className="absolute top-0 right-0 px-2 py-1 bg-purple-500 text-white text-[10px] font-bold rounded-bl-lg flex items-center gap-1">
                                <Infinity size={10} /> {t.rechargeCredits.monthly}
                            </div>
                            <div className="flex items-center gap-3 mb-3">
                                <div className="p-2 bg-purple-500/20 rounded-full text-purple-400">
                                    <ShieldCheck size={20} />
                                </div>
                                <div>
                                    <h4 className="font-bold text-white text-sm">{t.rechargeCredits.activateMonitoring}</h4>
                                    <p className="text-xs text-purple-200/70">{t.rechargeCredits.theSource}</p>
                                </div>
                            </div>
                            <p className="text-xs text-gray-300 mb-3 leading-relaxed">
                                {t.rechargeCredits.monitoringUpsellDesc}
                            </p>
                            <div className="flex items-center gap-2 mb-3">
                                <span className="text-lg font-bold text-white">89€</span>
                                <span className="text-xs text-gray-500">{t.rechargeCredits.perMonth}</span>
                            </div>
                            <button className="w-full py-2 btn-gradient text-xs font-bold transition-colors">
                                {t.rechargeCredits.addSubscription}
                            </button>
                        </div>
                    )}

                    {!showCiterneUpsell && !showSubscriptionUpsell && (
                        <div className="p-5 rounded-2xl border border-[var(--border-subtle)] bg-white/[0.03] text-center">
                            <div className="w-12 h-12 bg-purple-400/10 rounded-full flex items-center justify-center text-purple-300 mx-auto mb-3">
                                <Check size={24} />
                            </div>
                            <p className="text-sm text-gray-300 font-medium">{t.rechargeCredits.bestOfferChosen}</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
  };

  const renderPaymentResult = () => {
    if (!selectedPack) return null;

    if (paymentStatus === 'error') {
        return (
            <div className="flex flex-col items-center justify-center min-h-[60vh] animate-in zoom-in duration-500 max-w-2xl mx-auto">
