                  <div className="space-y-2">
                    {['Experience', 'Expertise', 'Authority', 'Trust'].map((label, i) => (
                      <div key={label} className="flex items-center gap-2">
                        <span className="text-[10px] text-gray-500 w-16">{label}</span>
                        <div className="flex-1 h-2 bg-white/[0.06] rounded-full overflow-hidden">
                          <div className="h-full rounded-full transition-all" style={{ width: `${[72, 85, 60, 90][i]}%`, background: `linear-gradient(90deg, ${whiteLabel.primaryColor}, ${whiteLabel.secondaryColor})` }} />
                        </div>
                        <span className="text-[10px] text-gray-400 w-6 text-right">{[72, 85, 60, 90][i]}</span>
                      </div>
                    ))}
                  </div>
                </div>
              </div>

              <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-6 rounded-2xl border border-white/[0.06] opacity-60">
                <div className="flex items-center gap-3">
                  <div className="p-2.5 bg-purple-500/10 rounded-xl">
                    <Globe size={20} className="text-purple-400" />
                  </div>
                  <div className="flex-1">
                    <div className="flex items-center gap-2">
                      <h4 className="font-bold text-white text-sm">{t.account.customDomain}</h4>
                      <span className="text-[10px] bg-amber-500/10 text-amber-400 px-2 py-0.5 rounded-full border border-amber-500/20">{t.common.comingSoon}</span>
                    </div>
                    <p className="text-xs text-gray-500 mt-1">{t.account.customDomainDesc}</p>
                  </div>
                  <Lock size={16} className="text-[var(--text-disabled)]" />
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      </>)}

      {/* MODAL SUCCESS */}
      {upgradeModal && paymentStep === 'success' && createPortal(
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => !isProcessing && handleCloseUpgradeModal()} />
          <div className="relative bg-white/[0.03] border border-purple-500/20 rounded-2xl w-full max-w-lg shadow-2xl shadow-purple-500/10 max-h-[90vh] overflow-y-auto">
            <div className="p-8 text-center space-y-5">
              <div className="w-20 h-20 mx-auto rounded-full bg-green-500/10 border-2 border-green-500/20 flex items-center justify-center">
                <Check size={40} className="text-green-400" />
              </div>
              <div>
                <h2 className="text-xl font-bold text-white mb-2">{t.account.paymentConfirmed}</h2>
                <p className="text-sm text-gray-400">
                  {t.account.nowOnPlan} <span className="text-purple-400 font-bold">{upgradeModal.planName}</span>.
                </p>
              </div>
              <div className="bg-white/[0.03] rounded-xl border border-[var(--border-subtle)] p-4 space-y-2 text-left">
                <div className="flex justify-between text-sm">
                  <span className="text-gray-400">{t.account.amountCharged}</span>
                  <span className="text-white font-bold">{paidAmount.toFixed(2)} €</span>
                </div>
                <div className="flex justify-between text-sm">
                  <span className="text-gray-400">{t.account.paymentMethod}</span>
                  <span className="text-white">•••• 4242</span>
                </div>
                <div className="flex justify-between text-sm">
                  <span className="text-gray-400">{t.account.nextRenewal}</span>
                  <span className="text-white">{upgradeModal.newPrice}€{t.account.perMonth}</span>
                </div>
              </div>
              <div className="flex gap-3 pt-2">
                <button onClick={() => { handleCloseUpgradeModal(); setActiveTab('subscription'); }}
                  className="flex-1 px-4 py-2.5 text-sm text-gray-400 hover:text-white border border-white/[0.06] rounded-xl transition-colors">
                  {t.account.mySubscription}
                </button>
                <button onClick={() => { handleCloseUpgradeModal(); setActiveTab('billing'); }}
                  className="flex-1 px-4 py-2.5 bg-gradient-to-r from-purple-500 to-violet-600 hover:from-purple-600 hover:to-violet-700 text-white font-bold rounded-xl flex items-center justify-center gap-2 transition-all shadow-lg shadow-purple-500/20 text-sm">
                  <FileText size={16} /> {t.account.viewInvoice}
                </button>
              </div>
            </div>
          </div>
        </div>,
        document.body
      )}
    </div>
  );
};

export default Account;
